queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?expansions a :Expansions .
    ?expansions p:Airport_Expansion ?airport_expansion .
    ?expansions p:Increased_Capacity ?increased_capacity_f .
    FILTER(STR(?increased_capacity_f) = "1500 Passengers per day")
    BIND(?airport_expansion AS ?o0)
  }
  UNION
  {
    ?renovations a :Renovations .
    ?renovations p:Renovation ?renovation .
    ?renovations p:Increased_Capacity ?increased_capacity_f .
    FILTER(STR(?increased_capacity_f) = "1500 Passengers per day")
    BIND(?renovation AS ?o0)
  }
}

